import{_ as a,o as t,c,ai as o}from"./chunks/framework.CsYGeNYI.js";const b=JSON.parse('{"title":"WebChat","description":"","frontmatter":{"read_when":["调试 macOS WebChat 视图或 loopback 端口"],"summary":"macOS 应用如何嵌入 Gateway 网关 WebChat 以及如何调试","title":"WebChat","x-i18n":{"generated_at":"2026-02-03T07:52:46Z","model":"claude-opus-4-5","provider":"pi","source_hash":"04ff448758e530098e2004625f33e42fc3dbe31137cd3beec2d55590e507de08","source_path":"platforms/mac/webchat.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/webchat.md","filePath":"zh-CN/platforms/mac/webchat.md","lastUpdated":null}'),s={name:"zh-CN/platforms/mac/webchat.md"};function i(d,e,l,h,n,r){return t(),c("div",null,[...e[0]||(e[0]=[o('<h1 id="webchat-macos-应用" tabindex="-1"><a class="header-anchor" href="#webchat-macos-应用">#</a> WebChat（macOS 应用）</h1><p>macOS 菜单栏应用将 WebChat UI 嵌入为原生 SwiftUI 视图。它连接到 Gateway 网关，默认使用所选智能体的<strong>主会话</strong>（带有会话切换器用于其他会话）。</p><ul><li><strong>本地模式</strong>：直接连接到本地 Gateway 网关 WebSocket。</li><li><strong>远程模式</strong>：通过 SSH 转发 Gateway 网关控制端口，并使用该隧道作为数据平面。</li></ul><h2 id="启动和调试" tabindex="-1"><a class="header-anchor" href="#启动和调试">#</a> 启动和调试</h2><ul><li>手动：Lobster 菜单 → &quot;Open Chat&quot;。</li><li>测试时自动打开：<div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dist/OpenSoul.app/Contents/MacOS/OpenSoul</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --webchat</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li>日志：<code>./scripts/opensoul-log.sh</code>（子系统 <code>ai.opensoul</code>，类别 <code>WebChatSwiftUI</code>）。</li></ul><h2 id="工作原理" tabindex="-1"><a class="header-anchor" href="#工作原理">#</a> 工作原理</h2><ul><li>数据平面：Gateway 网关 WS 方法 <code>chat.history</code>、<code>chat.send</code>、<code>chat.abort</code>、<code>chat.inject</code> 和事件 <code>chat</code>、<code>agent</code>、<code>presence</code>、<code>tick</code>、<code>health</code>。</li><li>会话：默认为主会话（<code>main</code>，或当范围为全局时为 <code>global</code>）。UI 可以在会话之间切换。</li><li>新手引导使用专用会话，以将首次运行设置分开。</li></ul><h2 id="安全面" tabindex="-1"><a class="header-anchor" href="#安全面">#</a> 安全面</h2><ul><li>远程模式仅通过 SSH 转发 Gateway 网关 WebSocket 控制端口。</li></ul><h2 id="已知限制" tabindex="-1"><a class="header-anchor" href="#已知限制">#</a> 已知限制</h2><ul><li>UI 针对聊天会话优化（不是完整的浏览器沙箱）。</li></ul>',11)])])}const u=a(s,[["render",i]]);export{b as __pageData,u as default};
